#!/usr/bin/env python3
"""Run ruff check on Python edits and surface linting errors."""
import json, subprocess, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    # Only check Python file edits
    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    # Run ruff check on the edited file
    try:
        result = subprocess.run(
            ["ruff", "check", file_path],
            capture_output=True,
            text=True,
            timeout=10
        )
        if result.returncode != 0:
            # Surface ruff errors with action-forcing phrasing
            msg = f"REQUIRED FOLLOW-UP: ruff check found issues in {file_path}:\n{result.stdout}"
            msg += "Fix each, then summarize. Do not stop."
            print(msg, file=sys.stderr)
            return 2
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json
import sys
import subprocess
import re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    old_string = inp.get("old_string", "")
    new_string = inp.get("new_string", "")

    if not all([file_path, old_string, new_string]):
        return 0

    if not file_path.endswith(('.ts', '.tsx')):
        return 0

    old_exports = re.findall(r'export\s+(?:const|let|var|function|interface|type|class)\s+(\w+)', old_string)
    new_exports = re.findall(r'export\s+(?:const|let|var|function|interface|type|class)\s+(\w+)', new_string)

    identifier = None
    if old_exports:
        identifier = old_exports[0]
    elif new_exports:
        identifier = new_exports[0]

    if not identifier:
        return 0

    try:
        result = subprocess.run(
            ["grep", "-r", f"\\b{identifier}\\b", "--exclude-dir=node_modules", "."],
            capture_output=True,
            text=True,
            timeout=10
        )

        if result.returncode in (0, 1):
            references = result.stdout.strip().split('\n') if result.stdout.strip() else []

            if references and references[0]:
                other_refs = [r for r in references if not r.startswith(file_path)]
                if other_refs:
                    msg = f"REQUIRED FOLLOW-UP: Exported identifier '{identifier}' was modified. Found {len(other_refs)} reference(s):\n" + '\n'.join(other_refs[:30])
                    if len(other_refs) > 30:
                        msg += f"\n... and {len(other_refs) - 30} more"
                    print(msg, file=sys.stderr)
    except Exception:
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Edit":
        return 0

    new_string = inp.get("new_string", "")
    file_path = inp.get("file_path", "")

    # Patterns for common API keys, tokens, passwords
    secret_patterns = [
        r'sk[-_]proj[-_][a-zA-Z0-9]{20,}',      # OpenAI
        r'sk[-_]ant[-_][a-zA-Z0-9]{20,}',       # Anthropic
        r'sk_live_[a-zA-Z0-9]{20,}',            # Stripe live
        r'sk_test_[a-zA-Z0-9]{20,}',            # Stripe test
        r'(api[_-]?key|password|secret|token)\s*[:=]\s*["\'][^"\']["\']',
    ]

    for pattern in secret_patterns:
        if re.search(pattern, new_string, re.IGNORECASE):
            msg = f"BLOCKING: Found secret pattern in {file_path}. Secrets must come from process.env, not hardcoded. See CLAUDE.md."
            print(msg, file=sys.stderr)
            return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys, re

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    command = inp.get("command", "")
    if "git commit" not in command:
        return 0

    # Extract commit message from -m \"...\" or --message=\"...\"
    patterns = [
        r'git\s+commit\s+(?:.*?\s+)?-m\s+\"([^\"]*)\"',
        r"git\s+commit\s+(?:.*?\s+)?-m\s+'([^']*)'",
        r'git\s+commit\s+(?:.*?\s+)?--message\s*=\s\"([^\"]*)\"',
        r"git\s+commit\s+(?:.*?\s+)?--message\s*=\s'([^']*)'",
    ]

    msg = None
    for pattern in patterns:
        match = re.search(pattern, command, re.DOTALL)
        if match:
            msg = match.group(1)
            break

    if not msg:
        return 0

    lines = msg.split('\n')
    subject = lines[0].strip()

    if not subject:
        return 0

    # Check: subject line should be short (under 72 chars is git convention)
    if len(subject) > 72:
        print("REQUIRED FOLLOW-UP: Commit message subject line is too long (72 char limit).\nUse short imperative format: 'Refactor auth: extract token validation'", file=sys.stderr)
        return 2

    # Check: if there's a second line, it should be blank (standard git format)
    if len(lines) > 1 and lines[1].strip() != "":
        print("REQUIRED FOLLOW-UP: After subject line, use blank line before body text.\nUse short imperative subject: 'Refactor auth: extract token validation'", file=sys.stderr)
        return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

